mapper.select:
SELECT oi.food_id as foodId, oi.food_name_snapshot as foodName, SUM(oi.quantity) as soldQuantity, SUM(oi.subtotal_amount) as soldAmount FROM order_items oi JOIN orders o ON oi.order_id = o.id WHERE o.order_status = 'PAID'
AND o.canteen_id = #{canteenId}
AND DATE(o.created_at) BETWEEN #{startDate} AND #{endDate} GROUP BY oi.food_id, oi.food_name_snapshot ORDER BY soldQuantity DESC
